 /* =================================================================
    RESPONSIVE NAV — md breakpoint (768px) matches original index.html
    Using vanilla @media to avoid Tailwind class-order issues.
    ================================================================= */

 /* Mobile-first: hamburger visible, desktop links hidden */
 .nav-desktop {
   display: none !important;
 }

 .nav-mobile-toggle {
   display: inline-flex;
 }

 /* md and up: desktop links visible, hamburger hidden */
 @media (min-width: 768px) {
   .nav-desktop {
     display: flex !important;
     align-items: center;
     gap: 1.5rem;
   }

   .nav-desktop-link {
     font-size: 1rem;
   }

   .nav-mobile-toggle {
     display: none !important;
   }
 }

 /* lg: a bit more gap between nav links */
 @media (min-width: 1024px) {
   .nav-desktop {
     gap: 2rem;
