===================================================================
--- web/src/styles/retro.css	
+++ web/src/styles/retro.css	
@@ -1,1887 +1,1887 @@
 /* Retro/paper theme for landing, tutorial, blog pages */
 /* Scope everything under .retro-layout to avoid polluting the chat theme */

 .retro-layout {
   --paper: #f1ece0;
   --paper-deep: #e9e2d2;
   --card: #f6f2e8;
   --ink: #1c211b;
   --ink-soft: #4a5247;
   --accent: #1e9b50;
   --accent-dim: #14743c;
   --green-wash: #ddebdd;
   --terminal: #0c1510;
   --terminal-edge: #1b2a1f;
   --phosphor: #4be388;
   --phosphor-dim: #2e9a5c;
   --amber: #e8a33d;
   --red: #d5604b;
   --line: rgba(28, 33, 27, 0.22);
   --line-soft: rgba(28, 33, 27, 0.12);
   --mono-display: 'Space Mono', ui-monospace, 'Cascadia Mono', Menlo, monospace;
   --mono-body: 'JetBrains Mono', ui-monospace, 'Cascadia Mono', Menlo, monospace;
   --shadow-card: 0 1px 0 rgba(28, 33, 27, 0.06), 0 10px 28px -18px rgba(28, 33, 27, 0.35);
   --nav-height: 3.5rem;

   font-family: var(--mono-body);
   background-color: var(--paper);
   color: var(--ink);
   line-height: 1.65;
   -webkit-font-smoothing: antialiased;
 }

 /* Dark mode: CRT phosphor palette */
 .dark .retro-layout {
   --paper: #0c1510;
   --paper-deep: #0a110d;
   --card: #11201a;
   --ink: #dcefe0;
   --ink-soft: #9dbfa8;
   --green-wash: rgba(75, 227, 136, 0.12);
   --line: rgba(75, 227, 136, 0.28);
   --line-soft: rgba(75, 227, 136, 0.14);
   --shadow-card: 0 1px 0 rgba(0, 0, 0, 0.4), 0 10px 28px -18px rgba(0, 0, 0, 0.8);
 }

 .dark .retro-layout.retro-page::before {
   opacity: 0.02;
 }

 /* Paper texture overlay — only on full-page retro layouts, not nav */
 .retro-layout.retro-page::before {
   content: '';
   position: fixed;
   top: 0;
   left: 0;
   right: 0;
   bottom: 0;
   background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 400 400' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E");
   opacity: 0.04;
   pointer-events: none;
   z-index: 1;
 }

 /* VT323 terminal font — works anywhere inside .retro-layout */
 .retro-layout .font-terminal {
   font-family: 'VT323', monospace;
 }

 .retro-layout .keating-title {
   font-family: 'VT323', monospace;
   font-size: 48px;
   color: var(--accent);
 }

 /* Nav link styling */
 .retro-layout .nav-link {
   color: var(--ink);
   text-decoration: none;
   transition: color 0.15s, text-shadow 0.15s;
   cursor: pointer;
   position: relative;
 }

 .retro-layout .nav-link:hover {
   color: var(--accent);
 }

 .retro-layout .nav-logo {
   border: 2px solid transparent;
   border-radius: 0.375rem;
   padding: 0.25rem 0.375rem;
   transition:
     background-color 0.15s ease,
     border-color 0.15s ease,
     color 0.15s ease,
     transform 0.15s ease,
     box-shadow 0.15s ease;
 }

 .retro-layout .nav-logo img {
   transition:
     transform 0.15s ease,
     filter 0.15s ease;
 }

 .retro-layout .nav-logo:hover,
 .retro-layout .nav-logo:focus-visible {
   border-color: color-mix(in srgb, var(--accent) 55%, transparent);
   background: color-mix(in srgb, var(--accent) 12%, transparent);
   color: var(--accent);
   box-shadow: 2px 2px 0 color-mix(in srgb, var(--accent) 55%, transparent);
   transform: translateY(-1px);
 }

 .retro-layout .nav-logo:hover img,
 .retro-layout .nav-logo:focus-visible img {
   filter: drop-shadow(0 0 6px color-mix(in srgb, var(--accent) 55%, transparent));
   transform: rotate(-3deg) scale(1.06);
 }

 .retro-layout .nav-logo:active {
   box-shadow: 1px 1px 0 color-mix(in srgb, var(--accent) 55%, transparent);
   transform: translate(1px, 1px);
 }

 /* ===== GLITCH HOVER — visible, no clip-path ===== */
 .retro-layout .glitch-hover {
   position: relative;
   transition: color 0.1s, text-shadow 0.1s;
 }

 .retro-layout .glitch-hover:hover {
   color: var(--accent);
   text-shadow: 2px 0 var(--phosphor), -2px 0 var(--accent);
   animation: retro-glitch 0.3s steps(3, end) infinite;
 }

 @keyframes retro-glitch {

   0%,
   100% {
     transform: translate(0);
   }

   20% {
     transform: translate(-2px, 1px);
   }

   40% {
     transform: translate(2px, -1px);
   }

   60% {
     transform: translate(-1px, -1px);
   }

   80% {
     transform: translate(1px, 2px);
   }
 }

 /* ===== BTN-RETRO — hard-shadow push button ===== */
 .retro-layout .btn-retro {
   padding: 10px;
   position: relative;
   display: inline-flex;
   align-items: center;
   justify-content: center;
   gap: 10px;
   min-height: 46px;
   overflow: hidden;
   isolation: isolate;
   background:
     linear-gradient(180deg, rgba(255, 255, 255, 0.36), transparent 48%),
     var(--card);
   border: 2px solid var(--ink);
   color: var(--ink);
   font-family: var(--mono-body);
   font-weight: 700;
   letter-spacing: 0.08em;
   text-transform: uppercase;
   text-shadow: 0 1px 0 rgba(255, 255, 255, 0.35);
   box-shadow:
     4px 4px 0 var(--ink),
     inset 0 -3px 0 color-mix(in srgb, var(--ink) 14%, transparent),
     inset 0 1px 0 rgba(255, 255, 255, 0.55);
   cursor: pointer;
   transition:
     color 0.14s ease,
     background-color 0.14s ease,
     border-color 0.14s ease,
     transform 0.14s ease,
     box-shadow 0.14s ease;
 }

 .retro-layout .btn-retro::before {
   content: '';
   position: absolute;
   inset: 0;
   z-index: 0;
   background: repeating-linear-gradient(90deg,
       transparent 0 9px,
       color-mix(in srgb, var(--ink) 6%, transparent) 9px 10px);
   opacity: 0;
   pointer-events: none;
   transition: opacity 0.14s ease;
 }

 .retro-layout .btn-retro::after {
   content: '';
   position: absolute;
   inset: 4px;
   z-index: 0;
   border: 1px solid color-mix(in srgb, var(--ink) 18%, transparent);
   opacity: 0.65;
   pointer-events: none;
 }

 .retro-layout .btn-retro:hover {
   transform: translate(-1px, -1px);
   background:
     linear-gradient(180deg, rgba(255, 255, 255, 0.4), transparent 45%),
     color-mix(in srgb, var(--accent) 12%, var(--card));
   box-shadow:
     5px 5px 0 var(--ink),
     inset 0 -3px 0 color-mix(in srgb, var(--ink) 14%, transparent),
     inset 0 1px 0 rgba(255, 255, 255, 0.6);
   color: var(--accent-dim);
 }

 .retro-layout .btn-retro:hover::before,
 .retro-layout .btn-retro:focus-visible::before {
   opacity: 1;
 }

 .retro-layout .btn-retro:active {
   transform: translate(3px, 3px);
   box-shadow:
     1px 1px 0 var(--ink),
     inset 0 2px 0 color-mix(in srgb, var(--ink) 18%, transparent);
 }

 .retro-layout .btn-retro:focus-visible {
   outline: 3px solid var(--accent);
   outline-offset: 3px;
 }

 .retro-layout .btn-retro-primary {
   background:
     linear-gradient(180deg, color-mix(in srgb, #fff 24%, transparent), transparent 48%),
     var(--accent);
   color: #fff;
   border-color: var(--accent-dim);
   padding: 10px;
   text-shadow: 0 1px 0 rgba(12, 21, 16, 0.35);
   box-shadow:
     4px 4px 0 var(--accent-dim),
     inset 0 -3px 0 color-mix(in srgb, var(--terminal) 22%, transparent),
     inset 0 1px 0 rgba(255, 255, 255, 0.34);
 }

 .retro-layout .btn-retro-primary:hover {
   background:
     linear-gradient(180deg, color-mix(in srgb, #fff 28%, transparent), transparent 48%),
     color-mix(in srgb, var(--accent) 86%, var(--phosphor));
   box-shadow:
     5px 5px 0 var(--accent-dim),
     inset 0 -3px 0 color-mix(in srgb, var(--terminal) 22%, transparent),
     inset 0 1px 0 rgba(255, 255, 255, 0.38);
   color: #fff;
 }

 .retro-layout .btn-retro-primary:active {
   box-shadow:
     1px 1px 0 var(--accent-dim),
     inset 0 2px 0 color-mix(in srgb, var(--terminal) 22%, transparent);
 }

 .dark .retro-layout .btn-retro-primary {
   color: var(--terminal);
 }

 /* ===== shared retro primitives (from brand reference) ===== */
 .retro-layout .eyebrow {
   font-family: var(--mono-body);
   font-size: 11px;
   letter-spacing: 0.18em;
   color: var(--accent-dim);
   text-transform: uppercase;
   font-weight: 600;
 }

 .dark .retro-layout .eyebrow {
   color: var(--phosphor);
 }

 .retro-layout .prompt::before {
   content: '$ ';
   color: var(--accent);
 }

 .retro-layout .card-retro {
   background: var(--card);
   border: 1.5px solid var(--ink);
   box-shadow: var(--shadow-card);
   transition:
     transform 0.14s ease,
     box-shadow 0.14s ease;
 }

 .retro-layout .card-retro:hover {
   transform: translateY(-3px);
   box-shadow: 5px 5px 0 var(--ink);
 }

 /* CRT panel: dark phosphor surface with scanlines */
 .retro-layout .crt-panel {
   position: relative;
   background: var(--terminal);
   border: 1.5px solid var(--ink);
   box-shadow: 6px 6px 0 var(--ink);
   color: var(--phosphor);
 }

 .retro-layout .crt-panel::after {
   content: '';
   position: absolute;
   inset: 0;
   pointer-events: none;
   background: repeating-linear-gradient(0deg,
       rgba(0, 0, 0, 0.16) 0 1px,
       transparent 1px 3px);
   mix-blend-mode: multiply;
 }

 /* ===== STATUS LED ===== */
 .retro-layout .status-led {
   width: 8px;
   height: 8px;
   border-radius: 50%;
   background: var(--accent);
   box-shadow: 0 0 8px var(--accent);
   animation: retro-pulse-led 2s ease-in-out infinite;
   flex-shrink: 0;
 }

 @keyframes retro-pulse-led {

   0%,
   100% {
     opacity: 1;
   }

   50% {
     opacity: 0.3;
   }
 }

 /* CRT scanline effect */
 .retro-layout .crt::before {
   content: '';
   position: absolute;
   top: 0;
   left: 0;
   right: 0;
   bottom: 0;
   background: repeating-linear-gradient(0deg,
       rgba(0, 0, 0, 0.03),
       rgba(0, 0, 0, 0.03) 1px,
       transparent 1px,
       transparent 2px);
   pointer-events: none;
   animation: retro-scanlines 0.1s linear infinite;
 }

 @keyframes retro-scanlines {
   0% {
     transform: translateY(0);
   }

   100% {
     transform: translateY(2px);
   }
 }

 /* Blinking cursor */
 .retro-layout .cursor-blink::after {
   content: '_';
   animation: retro-blink 1s step-end infinite;
   color: var(--accent);
 }

 @keyframes retro-blink {
   50% {
     opacity: 0;
   }
 }

 /* Terminal glow */
 .retro-layout .terminal-glow {
   box-shadow: 0 0 20px rgba(75, 227, 136, 0.25), inset 0 0 20px rgba(75, 227, 136, 0.05);
 }

 /* Typewriter effect */
 .retro-layout .typewriter {
   overflow: hidden;
   white-space: nowrap;
   animation: retro-typing 3.5s steps(40, end);
 }

 @keyframes retro-typing {
   from {
     width: 0;
   }

   to {
     width: 100%;
   }
 }

 /* Boot sequence animation */
 @keyframes retro-boot-line {
   0% {
     opacity: 0;
     transform: translateX(-10px);
   }

   100% {
     opacity: 1;
     transform: translateX(0);
   }
 }

 .retro-layout .boot-line {
   opacity: 0;
   animation: retro-boot-line 0.1s ease forwards;
 }

 /* Paper fold effect */
 .retro-layout .paper-fold {
   position: relative;
   background: var(--paper);
   box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1), 0 0 40px rgba(0, 0, 0, 0.05) inset;
 }

 .retro-layout .paper-fold::before {
   content: '';
   position: absolute;
   top: 0;
   left: 0;
   right: 0;
   height: 100%;
   background: linear-gradient(180deg, rgba(0, 0, 0, 0.02) 0%, transparent 100%);
   pointer-events: none;
 }

 /* Distressed border */
 .retro-layout .distressed-border {
   border: 2px solid var(--ink);
   position: relative;
 }

 .retro-layout .distressed-border::before {
   content: '';
   position: absolute;
   top: -2px;
   left: -2px;
   right: -2px;
   bottom: -2px;
   background: var(--paper);
   clip-path: polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%,
       0% 95%, 2% 95%, 2% 90%, 0% 90%,
       0% 85%, 3% 85%, 3% 80%, 0% 80%,
       0% 75%, 1% 75%, 1% 70%, 0% 70%,
       0% 65%, 2% 65%, 2% 60%, 0% 60%,
       0% 55%, 1% 55%, 1% 50%, 0% 50%,
       0% 45%, 3% 45%, 3% 40%, 0% 40%,
       0% 35%, 2% 35%, 2% 30%, 0% 30%,
       0% 25%, 1% 25%, 1% 20%, 0% 20%,
       0% 15%, 2% 15%, 2% 10%, 0% 10%,
       0% 5%, 1% 5%, 1% 0%);
   z-index: -1;
 }

 /* Terminal window */
 .retro-layout .terminal-window {
   background: var(--terminal);
   color: var(--phosphor);
   font-family: 'VT323', monospace;
   position: relative;
   overflow-wrap: break-word;
   word-break: break-word;
 }

 .retro-layout .terminal-window::before {
   content: '';
   position: absolute;
   top: 0;
   left: 0;
   right: 0;
   bottom: 0;
   background: repeating-linear-gradient(0deg,
       rgba(75, 227, 136, 0.04),
       rgba(75, 227, 136, 0.04) 1px,
       transparent 1px,
       transparent 2px);
   pointer-events: none;
 }

 /* Tape effect */
 .retro-layout .tape {
   position: relative;
 }

 .retro-layout .tape::before {
   content: '';
