/**
 * Procedural Three.js rendition of the Keating brand CRT monitor.
 * Built from primitives (no GLTF assets) so it ships as pure code and
 * always matches the brand palette. The screen hosts a live xterm.js
 * terminal running the Keating CLI front-end (see keating/hero-tui.ts).
 */
import { Canvas, useFrame } from "@react-three/fiber";
import { ContactShadows, Html, RoundedBox } from "@react-three/drei";
import { useEffect, useMemo, useRef } from "react";
import * as THREE from "three";
import { createHeroTui } from "../../keating/hero-tui";

const C = {
  cream: "#ece2cb",
  creamDark: "#ddd1b5",
  ink: "#26261f",
  green: "#1e9b50",
  bezel: "#15150f",
  screen: "#0c1510",
  ledRed: "#d5604b",
  ledAmber: "#e8a33d",
  ledGreen: "#43b964",
  button: "#5fbe72",
} as const;

// Screen plane is 1.86 × 1.12 world units. With drei <Html transform>,
// 1 div px = distanceFactor / 400 units, so a 520 × 313 px div needs:
const SCREEN_W = 1.86;
const SCREEN_DIV_W = 520;
const SCREEN_DIV_H = 313;
const SCREEN_DF = (SCREEN_W / SCREEN_DIV_W) * 400; // ≈ 1.43

function useMaterials() {
  return useMemo(() => {
    const mk = (color: string, rough = 0.55, metal = 0.05) =>
      new THREE.MeshStandardMaterial({ color, roughness: rough, metalness: metal });
    const led = (color: string) =>
      new THREE.MeshStandardMaterial({ color, emissive: color, emissiveIntensity: 0.5, roughness: 0.3 });
    return {
      cream: mk(C.cream, 0.5),
      creamDark: mk(C.creamDark, 0.6),
